import fs from "fs";
import path from "path";

const GENERATED_HEADER =
    "// AUTO-GENERATED FILE - DO NOT EDIT\n// Generated by globalSetup for parallel test execution\n// Regenerated on every test run and in watch mode\n";

/**
 * Generates one test file per fixture directory for full parallel execution.
 *
 * Instead of a single test file that loads all fixtures in beforeAll and runs them
 * sequentially in one worker, this generates N individual test files — one per fixture —
 * so vitest can distribute them across all available worker threads.
 *
 * @param {Object} options
 * @param {string} options.fixturesDir - Absolute path to directory containing fixture subdirectories
 * @param {string} options.outputDir - Absolute path to directory where test files will be generated
 * @param {string} options.testRunnerImport - Import path for the test runner module (relative to outputDir)
 * @param {string} options.testRunnerFunction - Name of the exported function to call in each test
 * @param {Object} [options.statics] - Static parameters to pass to the runner function (serialized as JSON)
 * @param {(name: string) => Object} [options.getFixtureArgs] - Optional function to compute per-fixture args
 * @param {number} [options.timeout] - Test timeout in ms (default: 30_000)
 */
export function generateTestsFromDirectory({
    fixturesDir,
    outputDir,
    testRunnerImport,
    testRunnerFunction,
    statics = {},
    getFixtureArgs,
    timeout = 30_000
}) {
    const fixtureNames = fs
        .readdirSync(fixturesDir, { withFileTypes: true })
        .filter((d) => d.isDirectory())
        .map((d) => d.name)
        .sort();

    fs.mkdirSync(outputDir, { recursive: true });

    // Track which files we generate so we can clean up stale ones
    const generatedFiles = new Set();

    for (const name of fixtureNames) {
        const fileName = `${name}.test.ts`;
        generatedFiles.add(fileName);

        const fixtureArgs = getFixtureArgs ? getFixtureArgs(name) : {};
        const allArgs = { ...statics, ...fixtureArgs, fixtureName: name };
        // Indent JSON args with 8 spaces (2 levels of 4-space indent) for biome formatting
        const argsJson = JSON.stringify(allArgs, null, 4).replace(/\n/g, "\n        ");

        const content = `${GENERATED_HEADER}
import { ${testRunnerFunction} } from "${testRunnerImport}";

it(${JSON.stringify(name)}, async () => {
    await ${testRunnerFunction}(${argsJson});
}, ${timeout});
`;

        const filePath = path.join(outputDir, fileName);

        // Only write if content changed to avoid unnecessary watch triggers
        const existing = fs.existsSync(filePath) ? fs.readFileSync(filePath, "utf-8") : null;
        if (existing !== content) {
            fs.writeFileSync(filePath, content);
        }
    }

    // Clean up test files for fixtures that no longer exist
    if (fs.existsSync(outputDir)) {
        for (const file of fs.readdirSync(outputDir)) {
            if (file.endsWith(".test.ts") && !generatedFiles.has(file)) {
                fs.unlinkSync(path.join(outputDir, file));
            }
        }
    }

    return fixtureNames;
}
